import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.interval.Month;
import com.google.common.collect.ImmutableList;
import com.google.common.collect.SetMultimap;
import com.google.common.collect.Sets;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;
import org.joda.time.LocalDateTime;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.stream.Collectors;

@Slf4j
public class StandaardRekenViaBoekDatumService implements RekenViaBoekDatumService {

    @Autowired
    private ArtikelHoofdService artikelHoofdService;
    @Autowired
    private RekenmotorService vormArtikelsRekenmotorService;
    @Autowired
    private RekenMotorStrategyFactory rekenMotorStrategyFactory;
    @Autowired
    private RekenenHelpService rekenenHelpService;
    @Autowired
    private MaandTotaalService maandTotaalService;
    @Autowired
    private HerrekenViaBoekDatumLogService herrekenViaBoekDatumLogService;
    @Autowired
    private LockLogService lockLogService;
    @Autowired
    private SNummerStaatService sNummerStaatService;
    @Autowired
    private CoreHrConfigurationService coreHrConfigurationService;

    private static final int REKENEN_ITEMNR = 9;

    private static final List<LockLogDTO> LOCKS = ImmutableList.of(new LockLogDTO(LockItemId.ALLPID, REKENEN_ITEMNR, LockType.SHARED),
            new LockLogDTO(LockItemId.ALLREKENAGENDA, REKENEN_ITEMNR, LockType.SHARED),
            new LockLogDTO(LockItemId.ALLWACHTAGENDA, REKENEN_ITEMNR, LockType.SHARED),
            new LockLogDTO(LockItemId.ALLMT, REKENEN_ITEMNR, LockType.EXCLUSIVE));

    @Override
    @SuppressWarnings("unchecked")
    @InitializeAdmin
    public MetaRekenFeedback start(Admin admin, String actor, RekenContext actionParams) {
        LocalDateTime now = LocalDateTime.now();
        Integer rnummer = actionParams.getInteger(RekenActionParamKey.RNUMMER_KEY);
        LocalDate boekDatum = (LocalDate) actionParams.get(RekenActionParamKey.BOEK_DATUM_KEY);
        List<ArtikelHoofd> artikelHoofden = (List<ArtikelHoofd>) actionParams.get(RekenActionParamKey.ARTIKEL_HOOFDEN_KEY);
        List<RekenHoofd> rekenHoofden = (List<RekenHoofd>) actionParams.get(RekenActionParamKey.REKEN_HOOFDEN_KEY);
        Integer boekjaar = actionParams.getInteger(RekenActionParamKey.BOEKJAAR_KEY);
        SetMultimap<RekenAtoom, Integer> rekenAtomenMap = (SetMultimap<RekenAtoom, Integer>) actionParams.get(RekenActionParamKey.REKEN_ATOMEN_KEY);
        Map<RekenAtoom, RekenAtoom> rekenAtomenOldMap = (Map<RekenAtoom, RekenAtoom>) actionParams.get(RekenActionParamKey.REKEN_ATOMEN_OLD_KEY);
        SetMultimap<RekenAtoom, Integer> atomenOldToOpdrachtNrMap =
                (SetMultimap<RekenAtoom, Integer>) actionParams.get(RekenActionParamKey.ATOMEN_OLD_TO_OPDRACHT_NR_KEY);
        MetaRekenFeedback metaRekenFeedback =
                doeBerekeningen(admin, artikelHoofden, rekenHoofden, boekDatum, boekjaar, rekenAtomenMap, rekenAtomenOldMap, atomenOldToOpdrachtNrMap, rnummer, actor,
                        now);
        resetSnummerOpArtikelHoofdenMaandTotalen(admin, rnummer);
        return metaRekenFeedback;
    }

    private void resetSnummerOpArtikelHoofdenMaandTotalen(Admin admin, Integer rnummer) {
        List<ArtikelHoofd> artikelHoofden = artikelHoofdService.findByRnummer(admin, rnummer);
        artikelHoofden.forEach(ah -> ah.setSnummer(rnummer));
        artikelHoofden.forEach(ah -> artikelHoofdService.update(admin, ah));
        maandTotaalService.resetSnummer(admin, rnummer);
    }

    public MetaRekenFeedback doeBerekeningen(
            Admin admin, List<ArtikelHoofd> artikelHoofden, List<RekenHoofd> rekenHoofden, LocalDate boekDatum, Integer boekjaar,
            SetMultimap<RekenAtoom, Integer> rekenAtomenMap,
            Map<RekenAtoom, RekenAtoom> rekenAtomenOldMap, SetMultimap<RekenAtoom, Integer> atomenOldToOpdrachtNrMap, Integer rnummer,
            String actor, LocalDateTime now) {
        Rekenmodus modus = Rekenmodus.VORM_ARTIKELS;
        MetaRekenFeedback metaFeedback = new MetaRekenFeedback(RekenActionType.HERREKEN_VIA_BOEKDATUM, modus);
        List<LockLog> lockedItems = new ArrayList<>();
        try {
            lockedItems = lockLogService.lockItems(admin, LOCKS, actor);
            CacheContext.getInstance().clearCachedServices(CacheContext.Scope.ALL);
            log.trace("doeBerekeningen(adminId:{} ({});", admin.getId(), admin.getAdminDirTrimmed());
            checkInterupted();

            if (rekenHoofden == null || rekenHoofden.isEmpty()) {
                rekenHoofden = artikelHoofden.stream().map(ArtikelHoofd::getRekenHoofd).collect(Collectors.toList());
            }
            aanmakenHerrekenViaBoekDatumLog(artikelHoofden, rekenHoofden, rnummer, boekDatum, actor, admin, now);
            deleteArtikelHoofdenEnMaandTotalen(admin, artikelHoofden, rnummer);
            metaFeedback.zetRekenAtomenSnummerEnTijdstipVerandering(rekenAtomenMap, rnummer, now.toString("yyyy-MM-dd HH:mm:ss"));
            schatAantalMaandOpdrachten(rekenAtomenMap.keySet());
            doeBerekeningenUitRekenAtomenNoCacheClear(admin, rekenAtomenMap, rekenAtomenOldMap, atomenOldToOpdrachtNrMap, rnummer, boekDatum, boekjaar, modus, actor,
                    metaFeedback);

        } finally {
            LockLogHelper lockLogHelper = new LockLogHelper(lockLogService, log);
            lockLogHelper.unlockItems(admin, lockedItems);
        }
        return metaFeedback;
    }

    private void aanmakenHerrekenViaBoekDatumLog(
            List<ArtikelHoofd> artikelHoofden, List<RekenHoofd> rekenHoofden, Integer rnummer, LocalDate boekDatum, String actor, Admin admin, LocalDateTime now) {
        ArtikelHoofd artikelHoofd = artikelHoofden.stream().findFirst().orElse(null);
        RekenHoofd rekenHoofd = rekenHoofden.stream().findFirst().orElse(null);
        HerrekenViaBoekDatumLog herrekenViaBoekDatumLog;
        if (artikelHoofd != null || rekenHoofd != null) {
            herrekenViaBoekDatumLog = new HerrekenViaBoekDatumLogPO();
            herrekenViaBoekDatumLog.setActor(actor);
            herrekenViaBoekDatumLog.setBoekDatumNieuw(boekDatum.dayOfMonth().withMinimumValue());
            if (artikelHoofd == null) {
                herrekenViaBoekDatumLog.setBoekDatumOud(rekenHoofd.getRekenDatum());
                herrekenViaBoekDatumLog.setOpdracht(rekenHoofd.getOpdracht());
                herrekenViaBoekDatumLog.setPeriode(rekenHoofd.getBeginDatum().withDayOfMonth(1));
            } else {
                herrekenViaBoekDatumLog.setBoekDatumOud(artikelHoofd.getBoekDatum());
                herrekenViaBoekDatumLog.setOpdracht(artikelHoofd.getRekenHoofd().getOpdracht());
                herrekenViaBoekDatumLog.setPeriode(artikelHoofd.getRekenHoofd().getBeginDatum().withDayOfMonth(1));
            }
            herrekenViaBoekDatumLog.setSnummer(rnummer);
            herrekenViaBoekDatumLog.setTijdstipVerandering(now);
            herrekenViaBoekDatumLogService.create(admin, herrekenViaBoekDatumLog);
        }
    }

    private void deleteArtikelHoofdenEnMaandTotalen(Admin admin, List<ArtikelHoofd> artikelHoofden, Integer rnummer) {
        maandTotaalService.deleteMetRnummer(admin, rnummer);
        if (artikelHoofden != null) {
            artikelHoofden.forEach(artikelHoofd -> artikelHoofdService.deleteArtikelHoofd(admin, artikelHoofd));
        }
    }

    private void checkInterupted() {
        if (RekenProcesImp.isInStopState()) {
            throw new ProcesHaltedException("Shall halt");
        }
    }

    private void schatAantalMaandOpdrachten(Set<RekenAtoom> rekenAtomen) {
        if (!rekenAtomen.isEmpty()) {
            RekenProcesImp.setTotaalStatic(rekenAtomen.size());
        } else {
            log.trace("Lege berekening");
            RekenProcesImp.setTotaalStatic(1);
            RekenProcesImp.incrementVerwerktStatic();
        }
    }

    private void doeBerekeningenUitRekenAtomenNoCacheClear(
            Admin admin, SetMultimap<RekenAtoom, Integer> atomenToOpdrachtNrMap,
            Map<RekenAtoom, RekenAtoom> rekenAtomenOldMap,
            SetMultimap<RekenAtoom, Integer> atomenOldToOpdrachtNrMap, Integer rnummer, LocalDate boekDatum,
            Integer boekjaar, Rekenmodus modus, String actor,
            MetaRekenFeedback metaFeedback) {
        RekenMotorStrategy strategy = rekenMotorStrategyFactory.getVormArtikelStrategy(admin);
        strategy.getArtikelMotorResultaatHandler().setRnummerVoorArtikelAgenda(rnummer);
        RekenLogStatus status = RekenLogStatus.SUCCES;

        CoreHrConfiguratie coreHrConfiguratie = coreHrConfigurationService.getCoreHrConfiguratie(admin);
        boolean resetBerekeningen = false;
        for (RekenAtoom atoom : atomenToOpdrachtNrMap.keySet()) {
            Set<Integer> opdrachtNrs = atomenToOpdrachtNrMap.get(atoom);
            RekenContext actionParams = new RekenContext();
            Set<LocalDateInterval> boekDatumIntervallen = Sets.newHashSet(new Month(boekDatum));
            actionParams.put(RekenChainKey.BOEK_DATUM_INTERVALLEN_SET_KEY, boekDatumIntervallen);
            checkInterupted();
            RekenFeedback rekenFeedback = null;
            try {
                RekenContext rekenContext = vormArtikelsRekenmotorService
                        .berekenLoon(admin, atoom.getPersoonId(), opdrachtNrs, atoom.getRekenTijd(), strategy, modus, actor, actionParams, coreHrConfiguratie);
                rekenFeedback = metaFeedback.rekenFeedbackPerAtoom(atoom, rekenContext.getUnchecked(RekenChainKey.REKEN_FEEDBACK_KEY));
                if (rekenFeedback.getAantalArtikelAgendas() > 0) {
                    resetBerekeningen = true;
                }
                RekenProcesImp.incrementVerwerktStatic();
            } catch (Exception exception) {
                rekenenHelpService.logFatalException(admin, atoom.getRekenTijd().beginDatum, atoom.getPersoonId(), opdrachtNrs, exception);
                status = RekenLogStatus.FATAL_ERROR;
            }
            doeRekenLog(admin, modus, actor, status, atoom, opdrachtNrs, rekenFeedback);
        }
        if (resetBerekeningen) {
            strategy.getArtikelMotorResultaatHandler().setIgnoreReguls(true);
            resetBerekeningenNaarOrigineel(admin, modus, actor, metaFeedback, strategy, rekenAtomenOldMap, atomenOldToOpdrachtNrMap, atomenToOpdrachtNrMap,
                    coreHrConfiguratie);
        } else {
            sNummerStaatService.updateBoekjaar(admin, metaFeedback.getSnummer(), boekDatum, boekjaar);
        }
    }

    private void doeRekenLog(
            Admin admin, Rekenmodus modus, String actor, RekenLogStatus status, RekenAtoom atoom, Set<Integer> opdrachtNrs, RekenFeedback rekenFeedback) {
        try {
            rekenenHelpService.doeRekenLog(admin, atoom.getPersoonId(), opdrachtNrs, atoom.getRekenTijd(), modus, status, rekenFeedback, actor);
        } catch (Exception exception) {
            log.debug("Logging failed", exception);
        }
    }

    private void resetBerekeningenNaarOrigineel(
            Admin admin, Rekenmodus modus, String actor, MetaRekenFeedback metaFeedback, RekenMotorStrategy strategy, Map<RekenAtoom, RekenAtoom> rekenAtomenOldMap,
            SetMultimap<RekenAtoom, Integer> atomenOldToOpdrachtNrMap,
            SetMultimap<RekenAtoom, Integer> atomenToOpdrachtNrMap,
            CoreHrConfiguratie coreHrConfiguratie) {
        RekenProcesImp.resetVerwerkt();
        schatAantalMaandOpdrachten(atomenOldToOpdrachtNrMap.keySet());
        for (RekenAtoom atoom : atomenToOpdrachtNrMap.keySet()) {
            RekenAtoom atoomOld = rekenAtomenOldMap.get(atoom);
            Set<Integer> opdrachtNrs = atomenToOpdrachtNrMap.get(atoom);
            LocalDate boekDatumOld = atoomOld.getRekenTijd().boekDatum;
            LocalDateInterval boekDatumIntervalOld = new LocalDateInterval(boekDatumOld.dayOfMonth().withMinimumValue(),
                    boekDatumOld.dayOfMonth().withMaximumValue());
            Set<LocalDateInterval> boekDatumIntervallenOld = Sets.newHashSet(boekDatumIntervalOld);
            RekenContext actionParamsOld = new RekenContext();
            actionParamsOld.put(RekenChainKey.BOEK_DATUM_INTERVALLEN_SET_KEY, boekDatumIntervallenOld);
            RekenFeedback rekenFeedback = null;
            RekenLogStatus status = RekenLogStatus.SUCCES;
            try {
                RekenContext rekenContext = vormArtikelsRekenmotorService
                        .berekenLoon(admin, atoomOld.getPersoonId(), opdrachtNrs, atoomOld.getRekenTijd(), strategy, modus,
                                actor, actionParamsOld, coreHrConfiguratie);
                rekenFeedback = metaFeedback.rekenFeedbackPerAtoom(atoom, rekenContext.getUnchecked(RekenChainKey.REKEN_FEEDBACK_KEY));
            } catch (Exception exception) {
                rekenenHelpService.logFatalException(admin, atoom.getRekenTijd().beginDatum, atoom.getPersoonId(), opdrachtNrs, exception);
                status = RekenLogStatus.FATAL_ERROR;
            }
            RekenProcesImp.incrementVerwerktStatic();
            doeRekenLog(admin, modus, actor, status, atoom, opdrachtNrs, rekenFeedback);
        }
        LocalDate boekDatumOld = rekenAtomenOldMap.values().stream().iterator().next().getRekenTijd().boekDatum;
        sNummerStaatService.updateBoekjaar(admin, metaFeedback.getSnummer(), boekDatumOld, 0);
    }
}
